<?php namespace App\Repositories\Asset;use App\Repositories\BaseRepository;use App\Models\Asset\Asset;use Illuminate\Database\Eloquent\Collection;use Illuminate\Pagination\LengthAwarePaginator;class AssetRepository extends BaseRepository{    public function __construct(Asset $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByCode(string $code): ?Asset    {        return $this->query()->where('asset_code', $code)->first();    }    public function findByName(string $name): Collection    {        return $this->query()->where('name', 'like', "%{$name}%")->get();    }    public function findByCategory(string $category): Collection    {        return $this->findByField('category', $category);    }    public function findByStatus(string $status): Collection    {        return $this->findByField('status', $status);    }    public function getActiveAssets(): Collection    {        return $this->query()->where('status', 'active')->get();    }    public function getUnderMaintenance(): Collection    {        return $this->query()->where('status', 'maintenance')->get();    }    public function getDisposedAssets(): Collection    {        return $this->query()->where('status', 'disposed')->get();    }    public function getByLocation(string $location): Collection    {        return $this->findByField('location', $location);    }    public function getByDepartment(int $departmentId): Collection    {        return $this->findByField('department_id', $departmentId);    }    public function searchAssets(string $keyword): Collection    {        return $this->query()->where('name', 'like', "%{$keyword}%")->orWhere('asset_code', 'like', "%{$keyword}%")->orWhere('serial_no', 'like', "%{$keyword}%")->orWhere('description', 'like', "%{$keyword}%")->get();    }    public function getByPurchaseDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('purchase_date', [$startDate, $endDate])->get();    }    public function getByValueRange(float $min, float $max): Collection    {        return $this->query()->whereBetween('purchase_cost', [$min, $max])->get();    }    public function countByCategory(): Collection    {        return $this->query()->selectRaw('category, COUNT(*) as total')->groupBy('category')->get();    }}